"use client"
import React from "react"
import { CartItem } from "@/app/page"
import {
 ShoppingBag,
 Truck,
 Info,
 Minus,
 Plus,
 CreditCard,
 ArrowRight
} from "lucide-react"

interface Props {
 cart: CartItem[]
 onUpdateQuantity: (id: number, delta: number) => void
 total: number
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <div className="flex flex-col h-full bg-white rounded-[2.5rem] border border-black/[0.03] font-manrope shadow-subtle hover:shadow-wow transition-all duration-500 ease-premium selection:bg-black/5">

   {/* ── Delivery Info Header ── */}
   <div className="p-8 border-b border-black/[0.03] flex items-center justify-between">
    <div className="flex items-center gap-3">
     <Truck className="w-6 h-6 text-meren-black" />
     <h2 className="text-[22px] font-[900] tracking-tight text-meren-black">30–60 мин, 0–219₽</h2>
    </div>
    <div className="h-6 w-6 rounded-full border border-black/10 flex items-center justify-center text-[12px] font-bold text-[#AEAEB2] cursor-help hover:bg-meren-light-gray transition-colors">
     <Info className="w-4 h-4" />
    </div>
   </div>

   {/* ── Body ── */}
   <div className="flex-1 overflow-y-auto px-8 py-6 smooth-scroll">
    {cart.length === 0 ? (
     <div className="flex h-full flex-col items-center justify-center py-10 anim-slide-up">
      {/* Larger Sad Paper Bag SVG */}
      <div className="relative mb-8">
       <svg width="160" height="160" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="drop-shadow-sm">
        <path d="M25 35L30 85H70L75 35H25Z" fill="#F5F5F7" />
        <path d="M25 35L35 25H65L75 35" stroke="#EBEBF0" strokeWidth="2" />
        <path d="M25 35C25 35 30 40 35 35C40 30 45 35 50 35C55 35 60 30 65 35C70 40 75 35 75 35" stroke="#EBEBF0" strokeWidth="2" strokeLinecap="round" />
        {/* x x eyes */}
        <path d="M40 55L46 61M46 55L40 61" stroke="#AEAEB2" strokeWidth="2.5" strokeLinecap="round" />
        <path d="M54 55L60 61M60 55L54 61" stroke="#AEAEB2" strokeWidth="2.5" strokeLinecap="round" />
        {/* mouth */}
        <path d="M44 70H56" stroke="#AEAEB2" strokeWidth="2.5" strokeLinecap="round" />
       </svg>
       <ShoppingBag className="absolute -bottom-2 -right-2 w-10 h-10 text-meren-black/5 rotate-12" />
      </div>
      <p className="text-[17px] font-bold text-center text-meren-black max-w-[220px] leading-tight mb-10 tracking-tight">
       В корзине пока ничего нет. Самое время наполнять её!
      </p>
      <button className="w-full bg-meren-light-gray text-meren-black/40 text-[15px] font-[900] py-5 rounded-[1.5rem] border-none cursor-default uppercase tracking-widest">
       Добавьте что-нибудь
      </button>
     </div>
    ) : (
     <div className="flex flex-col gap-8">
      {cart.map((item) => (
       <div key={item.id} className="group flex items-center gap-5 anim-slide-up">
        <div className="h-20 w-20 shrink-0 overflow-hidden rounded-2xl bg-[#F5F5F7] p-3 transition-colors group-hover:bg-[#EBEBF0]">
         <img src={item.image} alt="" className="h-full w-full object-contain mix-blend-multiply transition-transform group-hover:scale-110 duration-500 ease-premium" />
        </div>

        <div className="flex-1 min-w-0">
         <p className="text-[16px] font-black tracking-tight text-meren-black leading-tight line-clamp-1 mb-2">
          {item.name}
         </p>
         <div className="flex items-center gap-3">
          <div className="flex items-center gap-3 rounded-full border border-black/5 px-3 py-1 bg-[#F5F5F7]">
           <button
            onClick={() => onUpdateQuantity(item.id, -1)}
            className="text-[16px] font-bold text-[#AEAEB2] hover:text-meren-black cursor-pointer border-none bg-transparent active:scale-75 transition-all"
           ><Minus className="w-4 h-4" /></button>
           <span className="text-[13px] font-black text-meren-black min-w-[16px] text-center">{item.quantity}</span>
           <button
            onClick={() => onUpdateQuantity(item.id, 1)}
            className="text-[16px] font-bold text-[#AEAEB2] hover:text-meren-black cursor-pointer border-none bg-transparent active:scale-75 transition-all"
           ><Plus className="w-4 h-4" /></button>
          </div>
         </div>
        </div>

        <div className="text-right">
         <p className="text-[17px] font-black tracking-tighter text-meren-black">
          {item.price * item.quantity} ₽
         </p>
        </div>
       </div>
      ))}
     </div>
    )}
   </div>

   {/* ── Footer ── */}
   {cart.length > 0 && (
    <div className="p-8 border-t border-black/[0.03] bg-white">
     <div className="flex items-end justify-between mb-8">
      <div className="flex flex-col">
       <span className="text-[16px] font-black text-meren-gray lowercase tracking-tight">итого</span>
       <span className="text-[11px] font-black text-[#AEAEB2] uppercase tracking-widest mt-1">к оплате</span>
      </div>
      <div className="text-right flex items-baseline gap-1">
       <span className="text-[44px] font-[900] text-meren-black tracking-tighter leading-none">{total}</span>
       <span className="text-[20px] font-black text-meren-black/20">₽</span>
      </div>
     </div>

     <button className="group w-full rounded-[1.75rem] bg-meren-black py-5 text-[17px] font-[900] tracking-tight text-white transition-all hover:bg-black hover:scale-[1.02] active:scale-[0.98] border-none cursor-pointer shadow-bold flex items-center justify-center gap-3">
      <CreditCard className="w-5 h-5 opacity-50 group-hover:opacity-100 transition-opacity" />
      <span>Оформить заказ</span>
      <ArrowRight className="w-5 h-5 translate-x-0 group-hover:translate-x-1 transition-transform" />
     </button>
    </div>
   )}

  </div>
 )
}

export default CartSidebar
